1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G processing fee for empty item list", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0]).toEqual({ premium: 5 });
13	    });
14	    it.todo("returns base premium plus fee for a single sword (100 + 5 = 105)");
15	    it.todo("returns base premium plus fee for a single amulet (60 + 5 = 65)");
16	    it.todo("returns base premium plus fee for a single staff (80 + 5 = 85)");
17	    it.todo("returns base premium plus fee for a single potion (40 + 5 = 45)");
18	    it.todo("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165)");
19	  });
20	
21	  describe("Quote - components", () => {
22	    it.todo("returns 25G base premium per component (2 runes = 50 + 5 = 55)");
23	    it.todo("applies block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)");
24	    it.todo("does not apply block for 4 alike components (4 runes = 100 + 5 = 105)");
25	    it.todo("does not apply block for 3 different components (2 runes + 1 moonstone = 75 + 5 = 80)");
26	    it.todo("applies separate blocks for different component types (3 runes + 3 moonstones = 120 + 5 = 125)");
27	    it.todo("handles 7 alike components without block (7 runes = 175 + 5 = 180)");
28	  });
29	
30	  describe("Quote - item-level modifiers", () => {
31	    it.todo("adds 50% cursed surcharge to cursed item base premium");
32	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
33	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
34	    it.todo("does not apply high-enchantment surcharge for enchantment 4");
35	    it.todo("applies item-level modifiers only to the affected item in a multi-item policy");
36	  });
37	
38	  describe("Quote - policy-wide modifiers", () => {
39	    it.todo("applies 10% first insurance surcharge on policy base premium sum");
40	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
41	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
42	    it.todo("stacks all policy-wide modifiers (loyalty + first insurance + follow-up)");
43	  });
44	
45	  describe("Quote - rounding", () => {
46	    it.todo("rounds premium up in MHPCO favor (ceiling)");
47	  });
48	
49	  describe("Quote - errors", () => {
50	    it.todo("rejects unknown item type with an error");
51	  });
52	
53	  describe("Claim - standard reimbursement", () => {
54	    it.todo("applies 100G deductible per damaged item (500 damage to sword = 400 payout)");
55	    it.todo("returns remaining cap after payout");
56	    it.todo("reimburses component damage with deductible (200 damage to rune = 100 payout)");
57	  });
58	
59	  describe("Claim - enchantment and material clauses", () => {
60	    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
61	    it.todo("fully reimburses dragon material items then applies deductible");
62	    it.todo("applies 50% rule when both high enchantment >= 8 and dragon material");
63	    it.todo("does not apply enchantment clause below enchantment 8");
64	  });
65	
66	  describe("Claim - cap and multiple damages", () => {
67	    it.todo("applies deductible separately per damaged item in same event");
68	    it.todo("caps total payout at 2x insurance sum across multiple claims");
69	    it.todo("reduces payout to remaining cap when cap would be exceeded");
70	  });
71	
72	  describe("Claim - errors", () => {
73	    it.todo("rejects damage for item not covered by the policy");
74	    it.todo("rejects more damage entries of a type than policy covers");
75	    it.todo("rejects negative damage amount");
76	  });
77	
78	  describe("Integration - newcomer cursed sword", () => {
79	    it.todo("computes 165G for newcomer with cursed sword (100 + 50 curse + 10 first ins + 5 fee)");
80	  });
81	
82	  describe("Integration - long-standing customer second contract", () => {
83	    it.todo("computes 160G for long-standing customer second contract with cursed high-ench sword");
84	  });
85	});
